{
  "day": "1",
  "heading": "Drive from Manali to Khanjer",
  "sub_heading": "Drive Distance: 140 km | Drive Duration: 5-6 hours | Pick up point for Indiahikes trekkers: Beas Bridge, Manali",
  "details": "Leave from Beas Bridge, Manali, at 6:00 am. Drop off your cloakroom bag, collect your rentals, and offload if you have opted for it, at Khanjer base camp.  You will meet your trek leader here. On the way, you will have your breakfast.\nIndiahikes will arrange transport from Manali to Khanjer. The cost for this pick-up is ₹1750 (additional 5% GST). These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek."
}

{
  "day": "2",
  "heading": "Trek from Khanjer to Yolling",
  "sub_heading": "Trek Distance: 9.2 km | Altitude Gain: 11,564 ft to 12,345 ft",
  "details": "Easy-Moderate. Gradual climb through a series of switchbacks till Tharang."
}

{
  "day": "3",
  "heading": "Trek from Yolling to Zardong",
  "sub_heading": "Trek Distance: 12 km | Altitude Gain: 12,345 ft to 12,667 ft",
  "details": "Goes through the village route with farmlands on the right. You cross a river bridge and also come across a wide open field."
}

{
  "day": "4",
  "heading": "Trek from Zardong  to Palpu via Kesar Yon Choo | optional trek to Miyar Origin",
  "sub_heading": "Trek Distance: 12.5 km | Altitude Gain: 12,667 ft to 12,782 via 13,202 ft",
  "details": "Start with a descent, followed by a steep section towards Stupa. After that the trail is gradual. Landscape frequently changes colour."
}

{
  "day": "5",
  "heading": "Trek from Palpu to Gompa",
  "sub_heading": "Trek Distance: 12.5 km | Altitude Gain: 12,782 ft to 12,828 ft",
  "details": ""
}

{
  "day": "6",
  "heading": "Trek from Gompa to Tharang",
  "sub_heading": "Trek Distance: 7.5 km | Altitude Loss: 12,828 ft to 12,270 ft",
  "details": ""
}

{
  "day": "7",
  "heading": "Trek from Tharang to Khanjer. Drive to Manali",
  "sub_heading": "Trek Distance: 7.5 km | Trek Duration: 5-6 hours | Altitude Loss: 12,270 ft to 6,730 ft via 11,564 ft\nDrive Distance: 140 km | Drive Duration: 5-6 hours | Drop off point for Indiahikes trekkers: Beas Bridge, Manali",
  "details": "Indiahikes will arrange transport from Khanjer to Manali. The cost for this drop-off is ₹1750 (additional 5% GST). These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek.\nYou will be reaching Manali by 7 to 8.00 pm"
}
